import{_ as t,o as s,c as a,a2 as i}from"./chunks/framework.BYlK8ftn.js";const k=JSON.parse('{"title":"Playbook: Provision Cloudflare Pages deploy credentials","description":"","frontmatter":{},"headers":[],"relativePath":"operations/cloudflare-deploy.md","filePath":"operations/cloudflare-deploy.md","lastUpdated":1781953466000}'),o={name:"operations/cloudflare-deploy.md"};function r(n,e,l,h,p,d){return s(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="playbook-provision-cloudflare-pages-deploy-credentials" tabindex="-1">Playbook: Provision Cloudflare Pages deploy credentials <a class="header-anchor" href="#playbook-provision-cloudflare-pages-deploy-credentials" aria-label="Permalink to &quot;Playbook: Provision Cloudflare Pages deploy credentials&quot;">​</a></h1><p>This is a one-time, human-only setup. It produces the two secrets the GitHub Actions deploy workflow (<code>.github/workflows/deploy.yml</code>) needs to publish the <code>korovany</code> SPA to Cloudflare Pages.</p><p>Owner: <strong>Fl0p</strong> (account holder). Daedalus cannot perform this — it requires logging into the Cloudflare dashboard with the account owner&#39;s credentials.</p><h2 id="what-you-will-produce" tabindex="-1">What you will produce <a class="header-anchor" href="#what-you-will-produce" aria-label="Permalink to &quot;What you will produce&quot;">​</a></h2><ol><li><code>CLOUDFLARE_API_TOKEN</code> — a scoped API token.</li><li><code>CLOUDFLARE_ACCOUNT_ID</code> — your account identifier.</li></ol><p>Both are stored as <strong>GitHub Actions repository secrets</strong> on <code>Fl0p/korovany</code>.</p><blockquote><p><strong>Why GitHub secrets and not Paperclip project env vars:</strong> the deploy runs on GitHub&#39;s hosted runners. Only GitHub Actions secrets are injected there; Paperclip project env vars never reach the runner. So these must live in GitHub.</p></blockquote><h2 id="step-1-—-get-your-cloudflare-account-id" tabindex="-1">Step 1 — Get your Cloudflare Account ID <a class="header-anchor" href="#step-1-—-get-your-cloudflare-account-id" aria-label="Permalink to &quot;Step 1 — Get your Cloudflare Account ID&quot;">​</a></h2><ol><li>Log in to <a href="https://dash.cloudflare.com" target="_blank" rel="noreferrer">https://dash.cloudflare.com</a>.</li><li>Go to <strong>Workers &amp; Pages</strong>.</li><li>On the right sidebar, copy the <strong>Account ID</strong>. (Alternatively it is the hex string in the dashboard URL: <code>dash.cloudflare.com/&lt;ACCOUNT_ID&gt;</code>.)</li></ol><h2 id="step-2-—-create-a-scoped-api-token" tabindex="-1">Step 2 — Create a scoped API token <a class="header-anchor" href="#step-2-—-create-a-scoped-api-token" aria-label="Permalink to &quot;Step 2 — Create a scoped API token&quot;">​</a></h2><ol><li>Go to <a href="https://dash.cloudflare.com/profile/api-tokens" target="_blank" rel="noreferrer">https://dash.cloudflare.com/profile/api-tokens</a>.</li><li><strong>Create Token</strong> → <strong>Create Custom Token</strong> (Get started).</li><li>Name: <code>korovany-pages-deploy</code>.</li><li>Permissions: add <strong>Account → Cloudflare Pages → Edit</strong>.</li><li>Account Resources: <strong>Include → your account</strong>.</li><li>(Optional) TTL / IP filtering as you prefer.</li><li><strong>Continue to summary → Create Token</strong>.</li><li>Copy the token value now — it is shown only once.</li></ol><h2 id="step-3-—-create-the-pages-project-one-time" tabindex="-1">Step 3 — Create the Pages project (one time) <a class="header-anchor" href="#step-3-—-create-the-pages-project-one-time" aria-label="Permalink to &quot;Step 3 — Create the Pages project (one time)&quot;">​</a></h2><p>The project must exist before the first deploy. Easiest from your machine:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CLOUDFLARE_API_TOKEN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">the token from step 2</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CLOUDFLARE_ACCOUNT_ID</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">the id from step 1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wrangler</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pages</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> project</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> korovany</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --production-branch=main</span></span></code></pre></div><p>Or in the dashboard: <strong>Workers &amp; Pages → Create → Pages → Connect direct upload</strong>, name it <code>korovany</code>. (We deploy via Wrangler, so you do <strong>not</strong> need to connect a Git repo in the Cloudflare UI.)</p><h2 id="step-4-—-store-the-secrets-in-github" tabindex="-1">Step 4 — Store the secrets in GitHub <a class="header-anchor" href="#step-4-—-store-the-secrets-in-github" aria-label="Permalink to &quot;Step 4 — Store the secrets in GitHub&quot;">​</a></h2><p>Either via the CLI (from inside the repo):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> secret</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CLOUDFLARE_API_TOKEN</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">   --repo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Fl0p/korovany</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # paste token when prompted</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> secret</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CLOUDFLARE_ACCOUNT_ID</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --repo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Fl0p/korovany</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # paste account id when prompted</span></span></code></pre></div><p>Or in the UI: <strong>Settings → Secrets and variables → Actions → New repository secret</strong>, adding <code>CLOUDFLARE_API_TOKEN</code> and <code>CLOUDFLARE_ACCOUNT_ID</code>.</p><h2 id="step-5-—-trigger-the-first-deploy" tabindex="-1">Step 5 — Trigger the first deploy <a class="header-anchor" href="#step-5-—-trigger-the-first-deploy" aria-label="Permalink to &quot;Step 5 — Trigger the first deploy&quot;">​</a></h2><p>Once the secrets exist, merging the scaffold PR to <code>main</code> (or any subsequent push to <code>main</code>) runs the deploy and publishes to <code>https://korovany.pages.dev</code>.</p><h2 id="verifying" tabindex="-1">Verifying <a class="header-anchor" href="#verifying" aria-label="Permalink to &quot;Verifying&quot;">​</a></h2><ul><li>GitHub → <strong>Actions</strong> tab → latest <strong>Deploy</strong> run is green.</li><li>The &quot;Deploy to Cloudflare Pages&quot; step logs the deployment URL.</li><li>Visit <code>https://korovany.pages.dev</code> and confirm the hello-world page renders.</li></ul><h2 id="security-notes" tabindex="-1">Security notes <a class="header-anchor" href="#security-notes" aria-label="Permalink to &quot;Security notes&quot;">​</a></h2><ul><li>The token grants only <strong>Pages: Edit</strong> — least privilege for this job.</li><li>Never commit the token. It lives only in GitHub Actions secrets.</li><li>Rotate by creating a new token and re-running <code>gh secret set</code>; revoke the old one in the Cloudflare dashboard.</li></ul>`,25)])])}const g=t(o,[["render",r]]);export{k as __pageData,g as default};
